// Inspect GLB files - dump the JSON chunk and summarize.
const fs = require('fs');
const path = require('path');

function readGlb(file) {
  const buf = fs.readFileSync(file);
  const magic = buf.readUInt32LE(0);
  const version = buf.readUInt32LE(4);
  const length = buf.readUInt32LE(8);
  if (magic !== 0x46546C67) throw new Error('Not a GLB: ' + file);
  let offset = 12;
  const chunks = [];
  while (offset < length) {
    const chunkLength = buf.readUInt32LE(offset);
    const chunkType = buf.readUInt32LE(offset + 4);
    const data = buf.subarray(offset + 8, offset + 8 + chunkLength);
    chunks.push({ chunkType, data });
    offset += 8 + chunkLength;
  }
  const jsonChunk = chunks.find(c => c.chunkType === 0x4E4F534A);
  const binChunk = chunks.find(c => c.chunkType === 0x004E4942);
  const json = JSON.parse(jsonChunk.data.toString('utf8'));
  return { json, bin: binChunk ? binChunk.data : null };
}

function summarize(file) {
  const { json, bin } = readGlb(file);
  console.log('=== ' + path.basename(file) + ' ===');
  console.log('asset:', JSON.stringify(json.asset));
  if (json.animations) console.log('animations:', Object.keys(json.animations), '(', json.animations.length, ')');
  console.log('meshes:', json.meshes ? json.meshes.length : 0);
  if (json.meshes) {
    json.meshes.forEach((m, i) => {
      const prims = m.primitives.map(p => {
        const attrs = Object.keys(p.attributes || {});
        const targets = (p.targets || []).map(t => Object.keys(t));
        return { attrs, indices: !!p.indices, mode: p.mode, material: p.material, targets: targets.length, targetKeys: targets[0] };
      });
      console.log('  mesh[' + i + '] "' + m.name + '":', JSON.stringify(prims));
    });
  }
  console.log('materials:', json.materials ? json.materials.length : 0);
  if (json.materials) json.materials.forEach((m,i)=>console.log('  mat['+i+']', JSON.stringify(m)));
  console.log('accessors:', json.accessors ? json.accessors.length : 0);
  console.log('bufferViews:', json.bufferViews ? json.bufferViews.length : 0);
  console.log('buffers:', json.buffers ? json.buffers.length : 0, 'byteLength:', json.buffers && json.buffers[0] ? json.buffers[0].byteLength : 0);
  console.log('nodes:', json.nodes ? json.nodes.length : 0);
  if (json.nodes) {
    json.nodes.forEach((n,i)=>{
      const keys = Object.keys(n);
      console.log('  node['+i+']', JSON.stringify({name:n.name, mesh:n.mesh, children:n.children, skin:n.skin, translation:n.translation, rotation:n.rotation, scale:n.scale}));
    });
  }
  console.log('skins:', json.skins ? json.skins.length : 0);
  if (json.skins) console.log('  skin:', JSON.stringify(json.skins[0]));
  console.log('images:', json.images ? json.images.length : 0);
  console.log('textures:', json.textures ? json.textures.length : 0);
  if (bin) console.log('bin size:', bin.length);
}

const files = process.argv.slice(2);
for (const f of files) summarize(f);

